 1→/**
 2→ * Markdown → Telegram HTML 轉換器
 3→ * 只處理 agent 常用的安全子集，避免 parse error。
 4→ * code block 內不做任何二次轉換。
 5→ */
 6→
 7→function escHtml(s: string): string {
 8→  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
 9→}
10→
11→/**
12→ * 把 agent 輸出的 Markdown 文字轉為 Telegram HTML。
13→ * 回傳 { html, plain }，plain 是純文字 fallback（已 escape）。
14→ */
15→export function markdownToHtml(text: string): { html: string; plain: string } {
16→  const lines = text.split("\n");
17→  const out: string[] = [];
18→  let inCode = false;
19→  let codeLang = "";
20→  const codeLines: string[] = [];
21→
22→  for (let i = 0; i < lines.length; i++) {
23→    const line = lines[i];
24→
25→    // Code block 開/關
26→    if (/^```/.test(line)) {
27→      if (!inCode) {
28→        inCode = true;
29→        codeLang = line.slice(3).trim();
30→        codeLines.length = 0;
31→      } else {
32→        // 閉合
33→        const cls = codeLang ? ` class="language-${escHtml(codeLang)}"` : "";
34→        out.push(`<pre><code${cls}>${escHtml(codeLines.join("\n"))}</code></pre>`);
35→        inCode = false;
36→        codeLang = "";
37→      }
38→      continue;
39→    }
40→
41→    if (inCode) {
42→      codeLines.push(line);
43→      continue;
44→    }
45→
46→    // 正常行：inline 轉換
47→    out.push(convertInline(line));
48→  }
49→
50→  // 未閉合 code block → 當純文字 escape 輸出
51→  if (inCode) {
52→    out.push(`<pre><code>${escHtml(codeLines.join("\n"))}</code></pre>`);
53→  }
54→
55→  const html = out.join("\n");
56→  return { html, plain: escHtml(text) };
57→}
58→
59→/** 行內 Markdown → HTML（不處理巢狀） */
60→function convertInline(line: string): string {
61→  // blockquote
62→  if (/^>\s?/.test(line)) {
63→    const content = line.replace(/^>\s?/, "");
64→    return `<blockquote>${escHtml(content)}</blockquote>`;
65→  }
66→
67→  let s = escHtml(line);
68→
69→  // inline code（先處理，避免內容被其他 regex 改到）
70→  s = s.replace(/`([^`]+)`/g, "<code>$1</code>");
71→
72→  // bold: **text** or __text__
73→  s = s.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
74→  s = s.replace(/__(.+?)__/g, "<b>$1</b>");
75→
76→  // italic: *text* or _text_ （排除已轉的 <b> 裡的底線）
77→  s = s.replace(/(?<![<\w])\*([^*]+)\*(?![>\w])/g, "<i>$1</i>");
78→  s = s.replace(/(?<![<\w])_([^_]+)_(?![>\w])/g, "<i>$1</i>");
79→
80→  // strikethrough: ~~text~~
81→  s = s.replace(/~~(.+?)~~/g, "<s>$1</s>");
82→
83→  // links: [text](url) — 需對已 escape 的文字處理
84→  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
85→
86→  return s;
87→}
